update product
set status=#{status}
    , update_time = now()
where id=#{id}

UPDATE product
SET flash_stock = flash_stock - #{quantity},
    update_time = NOW()
WHERE id = #{id}
  AND flash_stock >= #{quantity}
  AND is_flash_sale = 1

